#!/usr/bin/env bash
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
GNOSIS_DIR="$(cd "${SCRIPT_DIR}/.." && pwd)"
REPO_ROOT="$(cd "${GNOSIS_DIR}/../.." && pwd)"

HOST="${HOST:-127.0.0.1}"
HTTP_PORT="${HTTP_PORT:-18787}"
FLOW_PORT="${FLOW_PORT:-19082}"
FLOW_WORKERS="${FLOW_WORKERS:-4}"
WALL_CLIENTS="${WALL_CLIENTS:-16}"
WALL_DEPTH="${WALL_DEPTH:-16}"
WALL_DURATION="${WALL_DURATION:-5s}"
WALL_MODE="${WALL_MODE:-udp}"
WALL_TCP_DELAY="${WALL_TCP_DELAY:-}"
WALL_UDP_DELAY="${WALL_UDP_DELAY:-0s}"
SERVER_PROFILE="${SERVER_PROFILE:-debug}"

if [[ -z "${WALL_TCP_DELAY}" ]]; then
  if [[ "${WALL_MODE}" == "race" ]]; then
    WALL_TCP_DELAY="250us"
  else
    WALL_TCP_DELAY="0s"
  fi
fi

WALL_BIN="${WALL_BIN:-${REPO_ROOT}/open-source/aeon/packages/wall/wall}"
SERVER_LOG="${SERVER_LOG:-${SCRIPT_DIR}/target/fano-xor-wall-server.log}"

if [[ ! -x "${WALL_BIN}" ]]; then
  echo "building wall: ${WALL_BIN}" >&2
  (cd "${REPO_ROOT}/open-source/aeon/packages/wall" && go build -o wall ./cmd/wall)
fi

cargo_args=(build --manifest-path "${SCRIPT_DIR}/Cargo.toml" --bin gnosis-foil-control)
server_bin="${SCRIPT_DIR}/target/debug/gnosis-foil-control"
if [[ "${SERVER_PROFILE}" == "release" ]]; then
  cargo_args=(build --release --manifest-path "${SCRIPT_DIR}/Cargo.toml" --bin gnosis-foil-control)
  server_bin="${SCRIPT_DIR}/target/release/gnosis-foil-control"
elif [[ "${SERVER_PROFILE}" != "debug" ]]; then
  echo "SERVER_PROFILE must be debug or release, got: ${SERVER_PROFILE}" >&2
  exit 2
fi

cargo "${cargo_args[@]}"

mkdir -p "$(dirname "${SERVER_LOG}")"
"${server_bin}" \
  --host "${HOST}" \
  --port "${HTTP_PORT}" \
  --flow-port "${FLOW_PORT}" \
  --flow-workers "${FLOW_WORKERS}" \
  --no-probability-admission \
  >"${SERVER_LOG}" 2>&1 &
server_pid=$!

cleanup() {
  kill "${server_pid}" >/dev/null 2>&1 || true
  wait "${server_pid}" >/dev/null 2>&1 || true
}
trap cleanup EXIT

for _ in $(seq 1 100); do
  if (echo >"/dev/tcp/${HOST}/${HTTP_PORT}") >/dev/null 2>&1; then
    break
  fi
  if ! kill -0 "${server_pid}" >/dev/null 2>&1; then
    echo "gnosis-foil-control exited before readiness; log follows:" >&2
    cat "${SERVER_LOG}" >&2
    exit 1
  fi
  sleep 0.05
done

if ! (echo >"/dev/tcp/${HOST}/${HTTP_PORT}") >/dev/null 2>&1; then
  echo "gnosis-foil-control did not become ready on ${HOST}:${HTTP_PORT}; log follows:" >&2
  cat "${SERVER_LOG}" >&2
  exit 1
fi

echo "server log: ${SERVER_LOG}" >&2
echo "wall mode: ${WALL_MODE}" >&2
echo "wall tcp delay: ${WALL_TCP_DELAY}" >&2
echo "wall udp delay: ${WALL_UDP_DELAY}" >&2

case "${WALL_MODE}" in
  udp)
    echo "wall target: aeon://${HOST}:${FLOW_PORT}/.aeon/fano-xor.bytes" >&2
    "${WALL_BIN}" \
      --bench \
      --udp \
      --raw-path \
      --clients "${WALL_CLIENTS}" \
      --duration "${WALL_DURATION}" \
      --depth "${WALL_DEPTH}" \
      "aeon://${HOST}:${FLOW_PORT}/.aeon/fano-xor.bytes"
    ;;
  race)
    echo "wall target: aeon://${HOST}:${FLOW_PORT}/.aeon/fano-xor.bytes + http://${HOST}:${HTTP_PORT}/.aeon/fano-xor.bytes" >&2
    "${WALL_BIN}" \
      --bench \
      --race \
      --udp \
      --raw-path \
      --tcp-delay "${WALL_TCP_DELAY}" \
      --udp-delay "${WALL_UDP_DELAY}" \
      --clients "${WALL_CLIENTS}" \
      --duration "${WALL_DURATION}" \
      --depth "${WALL_DEPTH}" \
      "aeon://${HOST}:${FLOW_PORT}/.aeon/fano-xor.bytes" \
      "http://${HOST}:${HTTP_PORT}/.aeon/fano-xor.bytes"
    ;;
  *)
    echo "WALL_MODE must be udp or race, got: ${WALL_MODE}" >&2
    exit 2
    ;;
esac
